    private int readExperienceYears() {
        try {
            String t = spinnerExperience.getEditor().getText();
            if (t == null || t.isBlank()) {
                Integer v = spinnerExperience.getValue();
                return v != null ? v : 0;
            }
            return Integer.parseInt(t.trim());
        } catch (NumberFormatException e) {
            return spinnerExperience.getValue() != null ? spinnerExperience.getValue() : 0;
        }
    }

    @FXML
    private void handleSaveButton(ActionEvent event) {
        hideMessage();
        if (!validateForm()) {
            showMessage("Veuillez corriger les erreurs dans le formulaire.");
            return;
        }

        try {
            User user;

            String email = emailField.getText().trim();
            String password = passwordField.getText();
            String phoneNorm = SignupFieldValidation.normalizePhone(telephoneField.getText());

            User userToUse;

            if (mode == Mode.EDIT && formateur != null && formateur.getUser() != null) {
                User dbUser = userService.getUserByEmail(formateur.getUser().getEmail());
                if (dbUser == null) {
                    dbUser = userService.findById(formateur.getUser().getId());
                }
                if (dbUser == null) {
                    showAlert("Erreur", "Utilisateur introuvable.", Alert.AlertType.ERROR);
                    return;
                }
                if (email.isEmpty()) {
                    showAlert("Erreur de validation", "L'email est obligatoire", Alert.AlertType.ERROR);
                    return;
                }
                if (userService.emailExists(email) && !email.equalsIgnoreCase(dbUser.getEmail())) {
                    showAlert("Erreur de validation", "Cet email existe déjà", Alert.AlertType.ERROR);
                    return;
                }
                dbUser.setEmail(email);
                dbUser.setNom(nomField.getText().trim());
                dbUser.setPrenom(prenomField.getText().trim());
                dbUser.setTelephone(phoneNorm);
                dbUser.setGouvernorat(gouvernoratField.getValue());
                LocalDate localDateEdit = dateNaissanceField.getValue();
                if (localDateEdit != null) {
                    dbUser.setDate_naissance(java.sql.Date.valueOf(localDateEdit));
                }
                String photoPathEdit = photoField.getText().trim();
                if (uploadedPhotoFile != null) {
                    photoPathEdit = fileUploadService.uploadPhoto(uploadedPhotoFile);
                }
                dbUser.setPhoto(photoPathEdit.isEmpty() ? null : photoPathEdit);
                userService.modifier(dbUser);
                userToUse = dbUser;
            } else if (!email.isEmpty() && password != null && !password.isEmpty()) {
                if (userService.emailExists(email)) {
                    showAlert("Erreur de validation", "Cet email existe déjà", Alert.AlertType.ERROR);
                    return;
                }

                User newUser = new User();
                newUser.setEmail(email);
                newUser.setPassword(password);
                newUser.setNom(nomField.getText().trim());
                newUser.setPrenom(prenomField.getText().trim());
                newUser.setTelephone(phoneNorm);
                newUser.setGouvernorat(gouvernoratField.getValue());
                newUser.setRole_utilisateur("formateur");
                newUser.setIs_email_verified(true);

                LocalDate localDate = dateNaissanceField.getValue();
                if (localDate != null) {
                    newUser.setDate_naissance(java.sql.Date.valueOf(localDate));
                }

                String photoPath = photoField.getText().trim();
                if (uploadedPhotoFile != null) {
                    photoPath = fileUploadService.uploadPhoto(uploadedPhotoFile);
                }
                newUser.setPhoto(photoPath.isEmpty() ? null : photoPath);

                userService.ajouter(newUser);
                userToUse = newUser;
            } else if (userComboBox != null && userComboBox.getValue() != null) {
                userToUse = userComboBox.getValue();
            } else {
                showAlert("Erreur de validation",
                    "Veuillez remplir l'email et le mot de passe pour créer un compte, ou sélectionner un utilisateur.",
                    Alert.AlertType.ERROR);
                return;
            }

            if (mode == Mode.ADD) {
                // Create new user for ADD mode
                user = new User();
                user.setPassword(passwordField.getText());
                formateur = new Formateur();
            } else {
                // Use existing user for EDIT mode
                user = formateur.getUser();
                // Only update password if provided
                if (!passwordField.getText().isEmpty()) {
                    user.setPassword(passwordField.getText());
                }
            }

            user.setEmail(trimToNull(emailTextField.getText()));
            user.setNom(trimToNull(nomTextField.getText()));
            user.setPrenom(trimToNull(prenomTextField.getText()));
            user.setTelephone(normalizePhone(telephoneTextField.getText()));
            Gouvernorat selectedGouvernorat = gouvernoratComboBox.getValue();
            user.setGouvernorat(selectedGouvernorat != null ? selectedGouvernorat.getDisplayName() : null);

            LocalDate birth = dateNaissancePicker.getValue();
            if (birth != null) {
                user.setDate_naissance(Date.from(birth.atStartOfDay(ZoneId.systemDefault()).toInstant()));
            }

            formateur.setUser(user);
            formateur.setSpecialite(specialiteTextField.getText().trim());
            formateur.setBio(bioTextArea.getText().trim().isEmpty() ? null : bioTextArea.getText().trim());

            int exp = experienceSpinner.getValue() != null ? experienceSpinner.getValue() : 0;
            formateur.setExperience_annees(exp > 0 ? exp : null);


            int experienceYears = readExperienceYears();
            if (experienceYears < 0 || experienceYears > 70) {
                showAlert("Erreur de validation", "L'expérience doit être comprise entre 0 et 70 ans", Alert.AlertType.ERROR);
                return;
            }
            formateur.setExperience_annees(experienceYears > 0 ? experienceYears : null);

            String linkedinText = linkedinTextField.getText().trim();
            formateur.setLinkedin(linkedinText.isEmpty() ? null : linkedinText);

            String portfolioText = portfolioTextField.getText().trim();
            formateur.setPortfolio(portfolioText.isEmpty() ? null : portfolioText);

            String cvText = cvTextField.getText().trim();
            formateur.setCv(cvText.isEmpty() ? null : cvText);
            if (uploadedCvFile != null) {
                cvText = fileUploadService.uploadCv(uploadedCvFile);
            }
            formateur.setCv(cvText.isEmpty() ? null : cvText);

            if (noteTextField != null) {
                String noteText = noteTextField.getText().trim();
                if (!noteText.isEmpty()) {
                    formateur.setNote_moyenne(Double.parseDouble(noteText));
                } else {
                    formateur.setNote_moyenne(null);
                }
            }

            formateur.setUser(userToUse);

            if (mode == Mode.ADD) {
                formateurService.ajouter(formateur);
                showMessage("Formateur créé avec succès.");
            } else {
                formateurService.modifier(formateur);
                showMessage("Formateur modifié avec succès.");
            }

            Platform.runLater(this::closeForm);
            closeForm();
        } catch (NumberFormatException e) {
            showAlert("Erreur de validation", "Vérifiez les valeurs numériques (expérience, note).", Alert.AlertType.ERROR);
        } catch (Exception e) {
            showMessage("Erreur lors de l'enregistrement: " + e.getMessage());
        }
    }

    @FXML
    private void handleCancelButton(ActionEvent event) {
        closeForm();
    }

    private boolean validateForm() {
        clearAllErrors();
        boolean isValid = true;

        // Validate user fields - email and phone are always required, password only for ADD mode
        isValid &= validateEmail();
        isValid &= validateTelephone();

        if (mode == Mode.ADD) {
            isValid &= validatePassword();
            isValid &= validatePasswordConfirm();
        } else {
            // For EDIT mode, only validate password if it's provided
            String password = passwordField.getText();
            if (!password.isEmpty()) {
                isValid &= validatePassword();
                isValid &= validatePasswordConfirm();
            }
        }

        isValid &= validateNom();
        isValid &= validatePrenom();
        isValid &= validateDateNaissance();

        // Validate formateur fields
        if (specialiteTextField.getText().trim().isEmpty()) {
            showError(errorSpecialite, "La spécialité est obligatoire");
            isValid = false;
        }


        String linkedinText = linkedinTextField.getText().trim();
        if (!linkedinText.isEmpty() && !isValidHttpUrl(linkedinText)) {
            showError(errorLinkedin, "L'URL LinkedIn doit commencer par http:// ou https://");
            isValid = false;
        }

        String portfolioText = portfolioTextField.getText().trim();
        if (!portfolioText.isEmpty() && !isValidHttpUrl(portfolioText)) {
            showError(errorPortfolio, "L'URL portfolio doit commencer par http:// ou https://");
            isValid = false;
        }

        String cvText = cvTextField.getText().trim();
        if (!cvText.isEmpty() && !isValidHttpUrl(cvText)) {
            showError(errorCv, "L'URL du CV doit commencer par http:// ou https://");
            isValid = false;
        }

        if (bioTextArea.getText() != null && bioTextArea.getText().trim().length() > 2000) {
            showError(errorBio, "La bio ne doit pas dépasser 2000 caractères");
            isValid = false;
        }

        return isValid;
    }

    private void setupValidationListeners() {
        // Email validation
        emailTextField.textProperty().addListener((obs, oldVal, newVal) -> {
            validateEmail();
        });

        // Telephone validation
        telephoneTextField.textProperty().addListener((obs, oldVal, newVal) -> {
            validateTelephone();
        });

        // Password validation
        passwordField.textProperty().addListener((obs, oldVal, newVal) -> {
            validatePassword();
            if (!passwordConfirmField.getText().isEmpty()) {
                validatePasswordConfirm();
            }
        });

        // Password confirmation validation
        passwordConfirmField.textProperty().addListener((obs, oldVal, newVal) -> {
            validatePasswordConfirm();
        });

        // Name validations
        nomTextField.textProperty().addListener((obs, oldVal, newVal) -> {
            validateNom();
        });

        prenomTextField.textProperty().addListener((obs, oldVal, newVal) -> {
            validatePrenom();
        });

        // Date validation
        dateNaissancePicker.valueProperty().addListener((obs, oldVal, newVal) -> {
            validateDateNaissance();
        });

        // Formateur field validations
        specialiteTextField.textProperty().addListener((obs, oldV, newV) -> {
            if (!newV.trim().isEmpty()) {
                hideError(errorSpecialite);
            }
        });
        linkedinTextField.textProperty().addListener((obs, oldV, newV) -> hideError(errorLinkedin));
        portfolioTextField.textProperty().addListener((obs, oldV, newV) -> hideError(errorPortfolio));
        cvTextField.textProperty().addListener((obs, oldV, newV) -> hideError(errorCv));
        bioTextArea.textProperty().addListener((obs, oldV, newV) -> hideError(errorBio));
    }

    private boolean isValidHttpUrl(String value) {
        String urlRegex = "^https?://[a-zA-Z0-9.-]+\\.[a-zA-Z]{2,}(/.*)?$";
        return Pattern.matches(urlRegex, value);
    }

    private void showMessage(String text) {
        lblMessage.setText(text);
        if (!lblMessage.getStyleClass().contains("signup-alert")) {
            lblMessage.getStyleClass().add("signup-alert");
        }
        lblMessage.setVisible(true);
        lblMessage.setManaged(true);
        Platform.runLater(() -> {
            lblMessage.requestLayout();
            scrollToMessageIfNeeded();
        });
    }

    private void hideMessage() {
        lblMessage.setText("");
        lblMessage.setVisible(false);
        lblMessage.setManaged(false);
    }

    private void scrollToMessageIfNeeded() {
        javafx.scene.Parent parent = lblMessage.getParent();
        while (parent != null) {
            if (parent instanceof ScrollPane scrollPane) {
                scrollPane.setVvalue(0);
                return;
            }
            parent = parent.getParent();
        }
    }

    private void showError(Label errorLabel, String message) {
        errorLabel.setText(message);
        errorLabel.setStyle("-fx-text-fill: #dc2626;");
        errorLabel.setVisible(true);
        errorLabel.setManaged(true);
    }

    private void hideError(Label errorLabel) {
        errorLabel.setText("");
        errorLabel.setStyle("");
        errorLabel.setVisible(false);
        errorLabel.setManaged(false);
    }

    private void clearAllErrors() {
        hideError(errorEmail);
        hideError(errorTelephone);
        hideError(errorPassword);
        hideError(errorPasswordConfirm);
        if (mode == Mode.EDIT) {
            return validateEditForm();
        }

        String email = emailField.getText().trim();
        String password = passwordField.getText();

        if (!email.isEmpty() || (password != null && !password.isEmpty())) {
            if (!SignupFieldValidation.isValidEmail(email)) {
                showAlert("Erreur de validation", "Email invalide ou manquant.", Alert.AlertType.ERROR);
                return false;
            }
            String phoneNorm = SignupFieldValidation.normalizePhone(telephoneField.getText());
            if (!SignupFieldValidation.isValidPhoneNormalized(phoneNorm)) {
                showAlert("Erreur de validation", "Téléphone invalide (8–12 chiffres).", Alert.AlertType.ERROR);
                return false;
            }
            String pwdErr = SignupFieldValidation.validatePasswordStrength(password != null ? password : "");
            if (pwdErr != null) {
                showAlert("Erreur de validation", pwdErr, Alert.AlertType.ERROR);
                return false;
            }
            String passwordConfirm = passwordConfirmField.getText();
            if (passwordConfirm == null || passwordConfirm.isEmpty()) {
                showAlert("Erreur de validation", "Confirmez le mot de passe.", Alert.AlertType.ERROR);
                return false;
            }
            if (!password.equals(passwordConfirm)) {
                showAlert("Erreur de validation", "Les mots de passe ne correspondent pas.", Alert.AlertType.ERROR);
                return false;
            }
            if (!SignupFieldValidation.isValidNomPrenom(nomField.getText())) {
                showAlert("Erreur de validation", "Le nom est obligatoire (min. 2 caractères).", Alert.AlertType.ERROR);
                return false;
            }
            if (!SignupFieldValidation.isValidNomPrenom(prenomField.getText())) {
                showAlert("Erreur de validation", "Le prénom est obligatoire (min. 2 caractères).", Alert.AlertType.ERROR);
                return false;
            }
            if (dateNaissanceField.getValue() == null) {
                showAlert("Erreur de validation", "La date de naissance est obligatoire", Alert.AlertType.ERROR);
                return false;
            }
            return true;
        }

        if (userComboBox != null && userComboBox.getValue() != null) {
            return true;
        }
        showAlert("Erreur de validation",
            "Renseignez email et mot de passe (comme à l'inscription) ou sélectionnez un utilisateur existant.",
            Alert.AlertType.ERROR);
        return false;
    }

    private boolean validateEditForm() {
        clearEditErrors();
        boolean valid = true;
        valid &= validateEditEmail();
        valid &= validateEditPhone();
        valid &= validateEditNom();
        valid &= validateEditPrenom();
        valid &= validateEditBirthDate();
        valid &= validateEditSpecialite();

        int experienceYears = readExperienceYears();
        if (experienceYears < 0 || experienceYears > 70) {
            showAlert("Erreur de validation", "L'expérience doit être comprise entre 0 et 70 ans", Alert.AlertType.ERROR);
            return false;
        }

        if (noteTextField != null) {
            String noteText = noteTextField.getText().trim();
            if (!noteText.isEmpty()) {
                try {
                    double note = Double.parseDouble(noteText);
                    if (note < 0 || note > 5) {
                        showAlert("Erreur de validation", "La note doit être comprise entre 0 et 5", Alert.AlertType.ERROR);
                        return false;
                    }
                } catch (NumberFormatException e) {
                    showAlert("Erreur de validation", "La note doit être un nombre", Alert.AlertType.ERROR);
                    return false;
                }
            }
        }

        return valid;
    }

    private boolean validateEditEmail() {
        if (!SignupFieldValidation.isValidEmail(emailField.getText().trim())) {
            showError(errorEmail, "Email invalide ou manquant.");
            return false;
        }
        hideError(errorEmail);
        return true;
    }

    private boolean validateEditPhone() {
        String phoneNorm = SignupFieldValidation.normalizePhone(telephoneField.getText());
        if (!SignupFieldValidation.isValidPhoneNormalized(phoneNorm)) {
            showError(errorTelephone, "Téléphone invalide (8-12 chiffres).");
            return false;
        }
        hideError(errorTelephone);
        return true;
    }

    private boolean validateEditNom() {
        if (!SignupFieldValidation.isValidNomPrenom(nomField.getText())) {
            showError(errorNom, "Le nom est obligatoire (min. 2 caractères).");
            return false;
        }
        hideError(errorNom);
        return true;
    }

    private boolean validateEditPrenom() {
        if (!SignupFieldValidation.isValidNomPrenom(prenomField.getText())) {
            showError(errorPrenom, "Le prénom est obligatoire (min. 2 caractères).");
            return false;
        }
        hideError(errorPrenom);
        return true;
    }

    private boolean validateEditBirthDate() {
        if (dateNaissanceField.getValue() == null) {
            showError(errorDateNaissance, "La date de naissance est obligatoire.");
            return false;
        }
        hideError(errorDateNaissance);
        return true;
    }

    private boolean validateEditSpecialite() {
        if (specialiteTextField.getText().trim().isEmpty()) {
            showError(errorSpecialite, "La spécialité est obligatoire.");
            return false;
        }
        hideError(errorSpecialite);
        return true;
    }

    private void clearEditErrors() {
        hideError(errorEmail);
        hideError(errorTelephone);
        hideError(errorNom);
        hideError(errorPrenom);
        hideError(errorDateNaissance);
        hideError(errorSpecialite);
        hideError(errorExperience);
        hideError(errorLinkedin);
        hideError(errorPortfolio);
        hideError(errorCv);
        hideError(errorBio);
    }

    private void showError(Label label, String msg) {
        if (label == null) {
            return;
        }
        label.setText(msg);
        label.setVisible(true);
        label.setManaged(true);
    }

    private void hideError(Label label) {
        if (label == null) {
            return;
        }
        label.setText("");
        label.setVisible(false);
        label.setManaged(false);
    }

    private void showAlert(String title, String message, Alert.AlertType alertType) {
        Alert alert = new Alert(alertType);
        alert.setTitle(title);
        alert.setHeaderText(null);
        alert.setContentText(message);
        alert.showAndWait();
    }

    private void closeForm() {
        if (cancelButton.getScene() != null && cancelButton.getScene().getWindow() != null) {
            cancelButton.getScene().getWindow().hide();
        }
    }

    // Validation methods
    private boolean validateEmail() {
        String email = emailTextField.getText().trim();
        if (email.isEmpty()) {
            showError(errorEmail, "L'email est obligatoire");
            return false;
        }

        String emailRegex = "^[A-Za-z0-9+_.-]+@([A-Za-z0-9.-]+\\.[A-Za-z]{2,})$";
        if (!Pattern.matches(emailRegex, email)) {
            showError(errorEmail, "Format d'email invalide");
            return false;
        }

        hideError(errorEmail);
        return true;
    }

    private boolean validateTelephone() {
        String telephone = telephoneTextField.getText().trim();
        if (telephone.isEmpty()) {
            showError(errorTelephone, "Le téléphone est obligatoire");
            return false;
        }

        String normalized = normalizePhone(telephone);
        if (normalized == null || !normalized.matches("\\+?[0-9]{8,12}$")) {
            showError(errorTelephone, "Format invalide: 8-12 chiffres");
            return false;
        }

        hideError(errorTelephone);
        return true;
    }

    private boolean validatePassword() {
        String password = passwordField.getText();

        // For EDIT mode, password is optional
        if (mode == Mode.EDIT && password.isEmpty()) {
            hideError(errorPassword);
            return true;
        }

        // For ADD mode, password is required
        if (password.isEmpty()) {
            showError(errorPassword, "Le mot de passe est obligatoire");
            return false;
        }

        if (password.length() < 8) {
            showError(errorPassword, "Minimum 8 caractères");
            return false;
        }

        if (!password.matches(".*[A-Z].*")) {
            showError(errorPassword, "Une majuscule requise");
            return false;
        }

        if (!password.matches(".*[a-z].*")) {
            showError(errorPassword, "Une minuscule requise");
            return false;
        }

        if (!password.matches(".*\\d.*")) {
            showError(errorPassword, "Un chiffre requis");
            return false;
        }

        hideError(errorPassword);
        return true;
    }

    private boolean validatePasswordConfirm() {
        String password = passwordField.getText();
        String passwordConfirm = passwordConfirmField.getText();

        // For EDIT mode, password confirmation is optional if password is empty
        if (mode == Mode.EDIT && password.isEmpty() && passwordConfirm.isEmpty()) {
            hideError(errorPasswordConfirm);
            return true;
        }

        // If password is provided, confirmation is required
        if (passwordConfirm.isEmpty()) {
            showError(errorPasswordConfirm, "La confirmation est obligatoire");
            return false;
        }

        if (!password.equals(passwordConfirm)) {
            showError(errorPasswordConfirm, "Les mots de passe ne correspondent pas");
            return false;
        }

        hideError(errorPasswordConfirm);
        return true;
    }

    private boolean validateNom() {
        String nom = nomTextField.getText().trim();
        if (nom.isEmpty()) {
            showError(errorNom, "Le nom est obligatoire");
            return false;
        }

        if (nom.length() < 2) {
            showError(errorNom, "Minimum 2 caractères");
            return false;
        }

        hideError(errorNom);
        return true;
    }

    private boolean validatePrenom() {
        String prenom = prenomTextField.getText().trim();
        if (prenom.isEmpty()) {
            showError(errorPrenom, "Le prénom est obligatoire");
            return false;
        }

        if (prenom.length() < 2) {
            showError(errorPrenom, "Minimum 2 caractères");
            return false;
        }

        hideError(errorPrenom);
        return true;
    }

    private boolean validateDateNaissance() {
        LocalDate date = dateNaissancePicker.getValue();
        if (date == null) {
            showError(errorDateNaissance, "La date de naissance est obligatoire");
            return false;
        }

        if (date.isAfter(LocalDate.now())) {
            showError(errorDateNaissance, "Date invalide");
            return false;
        }

        if (date.isBefore(LocalDate.now().minusYears(120))) {
            showError(errorDateNaissance, "Date invalide");
            return false;
        }

        hideError(errorDateNaissance);
        return true;
    }

    // Utility methods
    /** Retire espaces / séparateurs ; conserve un + initial. Doit matcher ^\\+?[0-9]{8,12}$ après nettoyage. */
    private static String normalizePhone(String raw) {
        if (raw == null) {
            return null;
        }
        String t = raw.trim();
        if (t.isEmpty()) {
            return null;
        }
        boolean plus = t.startsWith("+");
        String digits = t.replaceAll("\\D", "");
        if (digits.isEmpty()) {
            return plus ? "+" : "";
        }
        return plus ? "+" + digits : digits;
    }

    private static String trimToNull(String s) {
        if (s == null) {
            return null;
        }
        String t = s.trim();
        return t.isEmpty() ? null : t;
    }

    @FXML
    private void onTogglePassword() {
        togglePasswordField(passwordField, btnTogglePassword);
    }

    @FXML
    private void onTogglePasswordConfirm() {
        togglePasswordField(passwordConfirmField, btnTogglePasswordConfirm);
    }

    private void togglePasswordField(javafx.scene.control.PasswordField passwordField, Button toggleButton) {
        HBox parent = (HBox) toggleButton.getParent();

        // Find current password field (either PasswordField or TextField)
        javafx.scene.control.TextInputControl currentField = null;
        int fieldIndex = -1;

        for (int i = 0; i < parent.getChildren().size(); i++) {
            javafx.scene.Node node = parent.getChildren().get(i);
            if ((node instanceof PasswordField || node instanceof TextField) && !node.equals(toggleButton)) {
                currentField = (javafx.scene.control.TextInputControl) node;
                fieldIndex = i;
                break;
            }
        }

        if (currentField == null) return;

        if (currentField instanceof PasswordField currentPasswordField) {
            // Show plain text while keeping bidirectional sync with injected field.
            TextField visiblePassword = new TextField();
            visiblePassword.setPromptText(currentPasswordField.getPromptText());
            visiblePassword.getStyleClass().addAll(currentPasswordField.getStyleClass());
            visiblePassword.setStyle(currentPasswordField.getStyle());
            visiblePassword.textProperty().bindBidirectional(currentPasswordField.textProperty());

            parent.getChildren().set(fieldIndex, visiblePassword);

            if (toggleButton == btnTogglePassword) {
                eyeIcon.setVisible(false);
                eyeIcon.setManaged(false);
                eyeSlashIcon.setVisible(true);
                eyeSlashIcon.setManaged(true);
            } else if (toggleButton == btnTogglePasswordConfirm) {
                eyeIconConfirm.setVisible(false);
                eyeIconConfirm.setManaged(false);
                eyeSlashIconConfirm.setVisible(true);
                eyeSlashIconConfirm.setManaged(true);
            }
        } else if (currentField instanceof TextField visiblePasswordField) {
            // Restore the original injected PasswordField to keep listeners/validation stable.
            PasswordField targetField = toggleButton == btnTogglePassword ? passwordField : passwordConfirmField;
            if (targetField == null) {
                return;
            }

            visiblePasswordField.textProperty().unbindBidirectional(targetField.textProperty());
            targetField.setPromptText(visiblePasswordField.getPromptText());
            targetField.getStyleClass().setAll(visiblePasswordField.getStyleClass());
            targetField.setStyle(visiblePasswordField.getStyle());
            parent.getChildren().set(fieldIndex, targetField);

            if (toggleButton == btnTogglePassword) {
                eyeIcon.setVisible(true);
                eyeIcon.setManaged(true);
                eyeSlashIcon.setVisible(false);
                eyeSlashIcon.setManaged(false);
            } else if (toggleButton == btnTogglePasswordConfirm) {
                eyeIconConfirm.setVisible(true);
                eyeIconConfirm.setManaged(true);
                eyeSlashIconConfirm.setVisible(false);
                eyeSlashIconConfirm.setManaged(false);
            }
        }
    }

    @FXML
    private void onUploadCv() {
        FileChooser fileChooser = new FileChooser();
        fileChooser.setTitle("Choisir un fichier CV");

        // Set extension filters
        FileChooser.ExtensionFilter pdfFilter = new FileChooser.ExtensionFilter("Fichiers PDF", "*.pdf");
        FileChooser.ExtensionFilter docFilter = new FileChooser.ExtensionFilter("Documents Word", "*.doc", "*.docx");
        FileChooser.ExtensionFilter allFilter = new FileChooser.ExtensionFilter("Tous les fichiers", "*.*");

        fileChooser.getExtensionFilters().addAll(pdfFilter, docFilter, allFilter);
        fileChooser.setSelectedExtensionFilter(pdfFilter);

        // Show open dialog
        Stage stage = (Stage) btnUploadCv.getScene().getWindow();
        File selectedFile = fileChooser.showOpenDialog(stage);

        if (selectedFile != null) {
            uploadedCvFile = selectedFile;
            lblCvFileName.setText(selectedFile.getName());
            cvTextField.setText(selectedFile.getAbsolutePath());
        }
    }
}

/* ════════════════════════════════════════════════════════════
   FORMINI.TN – MODERN SAAS JavaFX STYLESHEET
   Style : Onix Digital Inspired
   ════════════════════════════════════════════════════════════ */

.root {
    -fx-primary: #6974e8;
    -fx-secondary: #8f94f6;
    -fx-accent: #ff4b5c;
    -fx-bg: #fdfdfd;
    -fx-surface: white;
    -fx-text: #2f3542;
    -fx-text-muted: #747d8c;
    -fx-success: #2ed573;
    -fx-warning: #ffa502;
    -fx-error: #ff4757;

    /* Onix Digital Gradients */
    -fx-primary-gradient: linear-gradient(to right, #6974e8, #8f94f6);
    -fx-banner-gradient: linear-gradient(from 0% 0% to 100% 100%, #6a85b6 0%, #bac8e0 100%);

    -fx-background-color: -fx-bg;
    -fx-font-family: 'Segoe UI', system-ui, -apple-system, sans-serif;
}

/* ── OAuth Button Styles ───────────────────────────────────── */
.btn-oauth {
    -fx-background-color: white;
    -fx-border-color: #d1d5db;
    -fx-border-width: 1;
    -fx-border-radius: 8;
    -fx-background-radius: 8;
    -fx-padding: 12 20;
    -fx-cursor: hand;
    -fx-font-size: 14px;
    -fx-font-weight: 500;
    -fx-text-fill: #374151;
}

.btn-oauth:hover {
    -fx-background-color: #f9fafb;
    -fx-border-color: #9ca3af;
    -fx-effect: dropshadow(gaussian, rgba(0, 0, 0, 0.1), 4, 0, 0, 1);
}

.btn-oauth:pressed {
    -fx-background-color: #f3f4f6;
}

.btn-google {
    -fx-border-color: #d1d5db;
}

.btn-google:hover {
    -fx-border-color: #4285f4;
}

.oauth-icon-google {
    -fx-font-size: 18px;
    -fx-font-weight: bold;
    -fx-text-fill: #4285f4;
}

.btn-github {
    -fx-border-color: #d1d5db;
}

.btn-github:hover {
    -fx-border-color: #333;
}

.oauth-icon-github {
    -fx-font-size: 18px;
    -fx-text-fill: #333;
}

.btn-cloudflare {
    -fx-border-color: #d1d5db;
}

.btn-cloudflare:hover {
    -fx-border-color: #f48120;
}

.oauth-icon-cloudflare {
    -fx-font-size: 18px;
    -fx-text-fill: #f48120;
}

.oauth-text {
    -fx-text-fill: #374151;
    -fx-font-size: 14px;
    -fx-font-weight: 500;
}

/* ── Sidebar Redesign ─────────────────────────────────────── */
.sidebar {
    -fx-background-color: #0f172a;
    -fx-effect: dropshadow(gaussian, rgba(0, 0, 0, 0.2), 30, 0, 0, 0);
}

.sidebar-logo {
    -fx-padding: 30px 24px;
    -fx-alignment: center-left;
}

.logo-icon-bg {
    -fx-background-color: -fx-primary-gradient;
    -fx-min-width: 40;
    -fx-min-height: 40;
    -fx-max-width: 40;
    -fx-max-height: 40;
    -fx-background-radius: 10;
}

.logo-icon-text {
    -fx-text-fill: white;
    -fx-font-size: 22;
    -fx-font-weight: bold;
}

.logo-text-bold {
    -fx-font-size: 18px;
    -fx-font-weight: 900;
    -fx-text-fill: white;
}

.logo-arabic {
    -fx-font-size: 14px;
    -fx-text-fill: #94a3b8;
    -fx-font-weight: bold;
}

.nav-accordion {
    -fx-background-color: transparent;
}

.nav-accordion .titled-pane {
    -fx-text-fill: #94a3b8;
    -fx-font-size: 14px;
    -fx-font-weight: 600;
}

.nav-accordion .titled-pane>.title {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-padding: 15px 24px;
}

.nav-accordion .titled-pane>.title:hover {
    -fx-background-color: rgba(255, 255, 255, 0.05);
    -fx-text-fill: white;
}

.nav-accordion .titled-pane:expanded>.title {
    -fx-text-fill: -fx-primary;
}

.nav-accordion .titled-pane>.content {
    -fx-background-color: #0f172a;
    -fx-border-color: transparent;
    -fx-padding: 0 0 10px 0;
}

.nav-sub {
    -fx-background-color: transparent;
    -fx-text-fill: #64748b;
    -fx-alignment: center-left;
    -fx-padding: 10px 24px 10px 48px;
    -fx-font-size: 13px;
    -fx-cursor: hand;
}

.nav-sub:hover {
    -fx-text-fill: white;
    -fx-background-color: rgba(255, 255, 255, 0.03);
}

/* ── Table System (Standardized) ────────────────────────────── */
.modern-table {
    -fx-background-color: white;
    -fx-background-radius: 20px;
    -fx-padding: 10px;
    -fx-effect: dropshadow(gaussian, rgba(0, 0, 0, 0.05), 15, 0, 0, 5);
    -fx-border-color: transparent;
}

.modern-table .column-header-background {
    -fx-background-color: #f8fafc;
    -fx-background-radius: 15px 15px 0 0;
}

.modern-table .column-header {
    -fx-background-color: transparent;
    -fx-size: 50px;
}

.modern-table .column-header .label {
    -fx-text-fill: #64748b;
    -fx-font-weight: 700;
    -fx-font-size: 13px;
}

.modern-table .table-row-cell {
    -fx-background-color: transparent;
    -fx-border-color: #f1f5f9;
    -fx-border-width: 0 0 1px 0;
    -fx-cell-size: 65px;
}

.modern-table .table-row-cell:hover {
    -fx-background-color: #f8faff;
}

/* ── Onix Digital Inspired Styles (Front) ────────────────── */
.hero-section {
    -fx-background-color: -fx-banner-gradient;
    -fx-background-radius: 40 40 150 40;
    -fx-padding: 100px 80px;
    -fx-effect: dropshadow(three-pass-box, rgba(106, 133, 182, 0.3), 30, 0, 0, 15);
}

.hero-title {
    -fx-text-fill: white;
    -fx-font-size: 48px;
    -fx-font-weight: 900;
}

.hero-subtitle {
    -fx-text-fill: rgba(255, 255, 255, 0.9);
    -fx-font-size: 20px;
    -fx-font-weight: 500;
}

.event-card {
    -fx-background-color: white;
    -fx-background-radius: 20px;
    -fx-padding: 0;
    -fx-border-color: #f0f0f0;
    -fx-border-width: 1px;
    -fx-border-radius: 20px;
    -fx-effect: dropshadow(three-pass-box, rgba(0, 0, 0, 0.05), 15, 0, 0, 5);
    -fx-cursor: hand;
}

.event-card:hover {
    -fx-translate-y: -10px;
    -fx-effect: dropshadow(three-pass-box, rgba(0, 0, 0, 0.1), 30, 0, 0, 15);
    -fx-border-color: #6974e8;
}

.card-image-cover {
    -fx-background-color: #f8f9fa;
    -fx-background-radius: 20 20 0 0;
    -fx-min-height: 160px;
    -fx-alignment: center;
}

.card-badge {
    -fx-background-color: -fx-primary;
    -fx-text-fill: white;
    -fx-padding: 5 15;
    -fx-background-radius: 5px;
    -fx-font-size: 11px;
    -fx-font-weight: bold;
}

.main-button-onix {
    -fx-background-color: -fx-primary;
    -fx-text-fill: white;
    -fx-padding: 12 35;
    -fx-background-radius: 25px;
    -fx-font-weight: bold;
    -fx-cursor: hand;
}

.card-title-lg {
    -fx-font-size: 18px;
    -fx-font-weight: 900;
    -fx-text-fill: #1e293b;
}

.section-heading-onix {
    -fx-font-size: 32px;
    -fx-font-weight: 900;
    -fx-text-fill: #1e293b;
}

.section-tag-onix {
    -fx-text-fill: -fx-primary;
    -fx-font-weight: bold;
    -fx-font-size: 14px;
    -fx-letter-spacing: 1px;
}

.view-all-link {
    -fx-text-fill: -fx-primary;
    -fx-font-weight: bold;
    -fx-underline: false;
}

/* ── ScrollPane Styling ────────────────────────────────────── */
.scroll-pane {
    -fx-background-color: transparent;
    -fx-background: transparent;
}

.scroll-pane .viewport {
    -fx-background-color: transparent;
}

.scroll-bar:vertical {
    -fx-background-color: transparent;
}

.scroll-bar:vertical .thumb {
    -fx-background-color: #cbd5e1;
    -fx-background-radius: 10;
}

/* ── Formulaires (admin / auth) ───────────────────────────── */
.content-area {
    -fx-background-color: transparent;
}

.page-title {
    -fx-font-size: 26px;
    -fx-font-weight: bold;
    -fx-text-fill: #1e293b;
}

.form-container {
    -fx-background-color: transparent;
}

.form-group {
    -fx-spacing: 6px;
}

.form-label {
    -fx-font-size: 13px;
    -fx-font-weight: 600;
    -fx-text-fill: #475569;
}

.form-control {
    -fx-background-radius: 10px;
    -fx-border-radius: 10px;
    -fx-border-color: #e2e8f0;
    -fx-border-width: 1px;
    -fx-background-color: #ffffff;
    -fx-padding: 10px 12px;
    -fx-font-size: 14px;
}

.form-control:focused {
    -fx-border-color: -fx-primary;
    -fx-effect: dropshadow(gaussian, rgba(105, 116, 232, 0.25), 8, 0, 0, 0);
}

.btn-primary {
    -fx-background-color: -fx-primary;
    -fx-text-fill: white;
    -fx-font-weight: bold;
    -fx-background-radius: 12px;
    -fx-padding: 12px 28px;
    -fx-cursor: hand;
}

.btn-primary:hover {
    -fx-background-color: derive(-fx-primary, -8%);
}

.btn-secondary {
    -fx-background-color: #f1f5f9;
    -fx-text-fill: #475569;
    -fx-font-weight: 600;
    -fx-background-radius: 12px;
    -fx-border-color: #e2e8f0;
    -fx-border-radius: 12px;
    -fx-border-width: 1px;
    -fx-padding: 12px 24px;
    -fx-cursor: hand;
}

.btn-secondary:hover {
    -fx-background-color: #e2e8f0;
}

.error-label {
    -fx-text-fill: -fx-error;
    -fx-font-size: 13px;
}

/* ── Page inscription (auth) ───────────────────────────────── */
.signup-page {
    -fx-background-color: linear-gradient(to bottom, #eef2ff 0%, #f8fafc 50%, #f1f5f9 100%);
}

.signup-column {
    -fx-padding: 0;
}

.signup-hero {
    -fx-padding: 0 4 0 4;
}

.signup-hero-kicker {
    -fx-text-fill: -fx-primary;
    -fx-font-size: 12px;
    -fx-font-weight: bold;
    -fx-letter-spacing: 0.08em;
}

.signup-hero-title {
    -fx-font-size: 28px;
    -fx-font-weight: bold;
    -fx-text-fill: #0f172a;
}

.signup-hero-sub {
    -fx-font-size: 14px;
    -fx-text-fill: #64748b;
    -fx-line-spacing: 2px;
}

.signup-alert {
    -fx-background-color: #fff1f2;
    -fx-background-radius: 12px;
    -fx-border-color: #fecdd3;
    -fx-border-radius: 12px;
    -fx-border-width: 1px;
    -fx-padding: 12px 16px;
    -fx-text-fill: #be123c;
    -fx-font-size: 13px;
}

.signup-card {
    -fx-background-color: #ffffff;
    -fx-background-radius: 20px;
    -fx-effect: dropshadow(gaussian, rgba(15, 23, 42, 0.08), 28, 0, 0, 6);
}

.signup-scroll {
    -fx-background-color: transparent;
    -fx-background: transparent;
    -fx-padding: 0;
}

.signup-scroll .viewport {
    -fx-background-color: transparent;
}

.signup-card-inner {
    -fx-background-color: transparent;
}

.signup-section-kicker {
    -fx-text-fill: -fx-primary;
    -fx-font-size: 11px;
    -fx-font-weight: bold;
    -fx-letter-spacing: 0.06em;
}

.signup-section-title {
    -fx-font-size: 17px;
    -fx-font-weight: bold;
    -fx-text-fill: #1e293b;
}

.signup-sep {
    -fx-opacity: 0.85;
}

.signup-role-row {
    -fx-padding: 0;
}

.signup-role-tile {
    -fx-background-color: #f8fafc;
    -fx-background-radius: 14px;
    -fx-border-color: #e2e8f0;
    -fx-border-radius: 14px;
    -fx-border-width: 1px;
    -fx-padding: 14px 16px;
    -fx-cursor: hand;
}

.signup-role-tile:hover {
    -fx-border-color: #c7d2fe;
    -fx-background-color: #f5f7ff;
}

.signup-role-tile-selected {
    -fx-background-color: #eef2ff;
    -fx-border-color: -fx-primary;
    -fx-border-width: 2px;
}

/* Enhanced Radio Button Styles */
.signup-role-radio .radio {
    -fx-background-color: #ffffff;
    -fx-border-color: #cbd5e1;
    -fx-border-width: 2px;
    -fx-background-radius: 8px;
    -fx-padding: 4px;
}

.signup-role-radio:selected .radio {
    -fx-background-color: -fx-primary;
    -fx-border-color: -fx-primary;
}

.signup-role-radio .dot {
    -fx-background-color: #ffffff;
    -fx-background-radius: 3px;
    -fx-padding: 3px;
}

.signup-role-radio:selected .dot {
    -fx-background-color: #ffffff;
    -fx-background-radius: 3px;
    -fx-padding: 3px;
}

/* Form field enhancements */
.form-control {
    -fx-background-color: #ffffff;
    -fx-border-color: #e2e8f0;
    -fx-border-width: 1px;
    -fx-background-radius: 10px;
    -fx-padding: 10px 14px;
    -fx-font-size: 14px;
    -fx-text-fill: #1e293b;
}

.form-control:focused {
    -fx-border-color: -fx-primary;
    -fx-border-width: 2px;
    -fx-background-radius: 9px;
}

.form-control:hover {
    -fx-border-color: #cbd5e1;
}

.error-label {
    -fx-text-fill: #dc2626;
    -fx-font-size: 12px;
    -fx-font-weight: 500;
    -fx-padding: 4px 0 0 0;
}

.signup-role-radio {
    -fx-font-size: 15px;
    -fx-font-weight: bold;
    -fx-text-fill: #1e293b;
}

.signup-role-hint {
    -fx-font-size: 12px;
    -fx-text-fill: #64748b;
}

.signup-grid {
    -fx-background-color: transparent;
}

.signup-field {
    -fx-min-height: 38px;
}

.signup-textarea {
    -fx-min-height: 100px;
}

.signup-field-hint {
    -fx-font-size: 12px;
    -fx-text-fill: #94a3b8;
}

.signup-actions {
    -fx-background-color: #fafbfc;
    -fx-border-color: #f1f5f9;
    -fx-border-width: 1px 0 0 0;
    -fx-background-radius: 0 0 20 20;
}

.signup-btn-primary {
    -fx-padding: 12px 32px;
    -fx-font-size: 14px;
}

.signup-btn-secondary {
    -fx-padding: 12px 24px;
}

.combo-box-base.signup-field,
.date-picker.signup-field,
.spinner.signup-field {
    -fx-background-radius: 10px;
}

/* Password Toggle Icons */
.btn-toggle-password-icon {
    -fx-min-width: 32px;
    -fx-max-width: 32px;
    -fx-min-height: 32px;
    -fx-max-height: 32px;
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-background-radius: 6px;
    -fx-cursor: hand;
    -fx-padding: 0;
}

.btn-toggle-password-icon:hover {
    -fx-background-color: #f1f5f9;
}

.btn-toggle-password-icon:pressed {
    -fx-background-color: #e2e8f0;
}

.icon-eye {
    -fx-font-size: 16px;
    -fx-text-fill: #64748b;
    -fx-alignment: center;
}

.icon-eye-slash {
    -fx-font-size: 16px;
    -fx-text-fill: #94a3b8;
    -fx-alignment: center;
}

/* Login Page Styles - Modern Design */
.login-page {
    -fx-background-color: linear-gradient(to bottom, #f0f4ff 0%, #fafbff 30%, #f8fafc 70%, #f1f5f9 100%);
}

/* Branding Section */
.login-branding {
    -fx-padding: 0 0 8 0;
}

.logo-container {
    -fx-cursor: hand;
}

.logo-bg {
    -fx-background-color: linear-gradient(to bottom right, #6974e8, #8f94f6);
    -fx-background-radius: 14px;
    -fx-min-width: 52px;
    -fx-min-height: 52px;
    -fx-max-width: 52px;
    -fx-max-height: 52px;
    -fx-alignment: center;
    -fx-effect: dropshadow(gaussian, rgba(105, 116, 232, 0.35), 16, 0, 0, 4);
}

.logo-letter {
    -fx-text-fill: white;
    -fx-font-size: 28px;
    -fx-font-weight: 900;
    -fx-font-family: 'Segoe UI', system-ui, sans-serif;
}

.brand-name {
    -fx-font-size: 24px;
    -fx-font-weight: 900;
    -fx-text-fill: #0f172a;
    -fx-font-family: 'Segoe UI', system-ui, sans-serif;
}

.brand-arabic {
    -fx-font-size: 12px;
    -fx-text-fill: #94a3b8;
    -fx-font-weight: 600;
    -fx-font-family: 'Segoe UI', system-ui, sans-serif;
}

/* Hero Section */
.login-hero {
    -fx-padding: 8 0 0 0;
}

.login-hero-kicker {
    -fx-text-fill: -fx-primary;
    -fx-font-size: 11px;
    -fx-font-weight: 800;
    -fx-letter-spacing: 0.12em;
    -fx-text-transform: uppercase;
}

.login-hero-title {
    -fx-font-size: 32px;
    -fx-font-weight: 800;
    -fx-text-fill: #0f172a;
    -fx-font-family: 'Segoe UI', system-ui, sans-serif;
}

.login-hero-sub {
    -fx-font-size: 14px;
    -fx-text-fill: #64748b;
    -fx-line-spacing: 3px;
    -fx-font-family: 'Segoe UI', system-ui, sans-serif;
}

/* Alert Styles */
.login-alert {
    -fx-background-color: white;
    -fx-background-radius: 12px;
    -fx-border-color: #fecdd3;
    -fx-border-width: 1px;
    -fx-border-radius: 12px;
    -fx-padding: 14px 18px;
    -fx-font-size: 13px;
    -fx-effect: dropshadow(gaussian, rgba(254, 205, 211, 0.3), 12, 0, 0, 4);
}

.login-alert-error {
    -fx-text-fill: #dc2626;
    -fx-background-color: #fef2f2;
    -fx-border-color: #fecaca;
}

.login-alert-success {
    -fx-text-fill: #059669;
    -fx-background-color: #f0fdf4;
    -fx-border-color: #bbf7d0;
}

.login-alert-info {
    -fx-text-fill: #2563eb;
    -fx-background-color: #eff6ff;
    -fx-border-color: #bfdbfe;
}

/* Login Card - Glassmorphism Effect */
.login-card {
    -fx-background-color: rgba(255, 255, 255, 0.95);
    -fx-background-radius: 24px;
    -fx-effect: dropshadow(gaussian, rgba(15, 23, 42, 0.12), 40, 0, 0, 8);
    -fx-border-color: rgba(255, 255, 255, 0.8);
    -fx-border-width: 1px;
    -fx-border-radius: 24px;
}

.login-card-inner {
    -fx-background-color: transparent;
}

/* Form Labels */
.login-section-kicker {
    -fx-text-fill: -fx-primary;
    -fx-font-size: 11px;
    -fx-font-weight: 800;
    -fx-letter-spacing: 0.08em;
    -fx-text-transform: uppercase;
}

.login-section-title {
    -fx-font-size: 18px;
    -fx-font-weight: 700;
    -fx-text-fill: #1e293b;
}

.login-sep {
    -fx-opacity: 0.5;
}

.login-grid {
    -fx-background-color: transparent;
}

/* Form Fields */
.login-field {
    -fx-min-height: 48px;
    -fx-font-size: 15px;
    -fx-background-color: #f8fafc;
    -fx-border-color: #e2e8f0;
    -fx-border-width: 2px;
    -fx-background-radius: 12px;
    -fx-border-radius: 12px;
    -fx-padding: 12px 16px;
}

.login-field:focused {
    -fx-background-color: white;
    -fx-border-color: #6974e8;
    -fx-effect: dropshadow(gaussian, rgba(105, 116, 232, 0.2), 12, 0, 0, 0);
}

.login-field:hover {
    -fx-border-color: #cbd5e1;
}

.login-field-hint {
    -fx-font-size: 12px;
    -fx-text-fill: #94a3b8;
}

/* Checkbox */
.login-checkbox {
    -fx-font-size: 14px;
    -fx-text-fill: #64748b;
    -fx-font-weight: 500;
}

.login-checkbox .box {
    -fx-background-color: #f8fafc;
    -fx-border-color: #e2e8f0;
    -fx-border-width: 2px;
    -fx-border-radius: 6px;
    -fx-background-radius: 6px;
}

.login-checkbox:selected .box {
    -fx-background-color: #6974e8;
    -fx-border-color: #6974e8;
}

.login-checkbox:selected .mark {
    -fx-background-color: white;
}

/* Links */
.login-link {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-text-fill: #6974e8;
    -fx-font-size: 14px;
    -fx-underline: false;
    -fx-cursor: hand;
    -fx-font-weight: 500;
}

.login-link:hover {
    -fx-text-fill: #5b21b6;
    -fx-underline: true;
}

.login-link-bold {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-text-fill: #6974e8;
    -fx-font-size: 14px;
    -fx-underline: false;
    -fx-cursor: hand;
    -fx-font-weight: 700;
}

.login-link-bold:hover {
    -fx-text-fill: #5b21b6;
    -fx-underline: true;
}

.login-text {
    -fx-font-size: 14px;
    -fx-text-fill: #64748b;
    -fx-font-weight: 500;
}

/* Buttons */
.login-btn-primary {
    -fx-padding: 14px 32px;
    -fx-font-size: 15px;
    -fx-font-weight: 700;
    -fx-background-color: linear-gradient(to bottom right, #6974e8, #8f94f6);
    -fx-background-radius: 12px;
    -fx-effect: dropshadow(gaussian, rgba(105, 116, 232, 0.35), 16, 0, 0, 4);
    -fx-cursor: hand;
}

.login-btn-primary:hover {
    -fx-background-color: linear-gradient(to bottom right, #5b21b6, #7c3aed);
    -fx-effect: dropshadow(gaussian, rgba(105, 116, 232, 0.5), 20, 0, 0, 6);
    -fx-translate-y: -1px;
}

.login-btn-primary:pressed {
    -fx-background-color: linear-gradient(to bottom right, #4c1d95, #6b21a8);
    -fx-effect: dropshadow(gaussian, rgba(105, 116, 232, 0.25), 8, 0, 0, 2);
    -fx-translate-y: 0px;
}

.login-btn-secondary {
    -fx-padding: 12px 24px;
}

/* Enhanced Login Button */
.login-btn-enhanced {
    -fx-padding: 16px 32px;
    -fx-font-size: 16px;
    -fx-font-weight: 800;
    -fx-letter-spacing: 0.5px;
    -fx-background-color: linear-gradient(to bottom right, #6974e8, #8f94f6, #6974e8);
    -fx-background-size: 200% 200%;
    -fx-background-insets: 0;
}

.login-btn-enhanced:hover {
    -fx-background-position: right center;
    -fx-padding: 17px 32px 15px 32px;
}

.login-btn-icon {
    -fx-font-size: 18px;
    -fx-effect: dropshadow(gaussian, rgba(255, 255, 255, 0.3), 2, 0, 0, 0);
}

/* Divider */
.login-divider {
    -fx-padding: 8 0 8 0;
}

.divider-line {
    -fx-background-color: #e2e8f0;
    -fx-min-height: 1px;
    -fx-max-height: 1px;
}

.divider-text {
    -fx-text-fill: #94a3b8;
    -fx-font-size: 13px;
    -fx-font-weight: 600;
}

/* Navigation styles */
.signup-nav {
    -fx-background-color: #fafbfc;
    -fx-border-color: #f1f5f9;
    -fx-border-width: 1px 0 0 0;
}

.signup-nav-text {
    -fx-font-size: 14px;
    -fx-text-fill: #64748b;
}

.signup-nav-link {
    -fx-background-color: transparent;
    -fx-border-color: transparent;
    -fx-text-fill: -fx-primary;
    -fx-font-size: 14px;
    -fx-font-weight: 500;
    -fx-underline: true;
    -fx-cursor: hand;
}

.signup-nav-link:hover {
    -fx-text-fill: #5b21b6;
}

/* File upload styles */
.signup-btn-upload {
    -fx-padding: 8px 16px;
    -fx-font-size: 13px;
}

.signup-file-name {
    -fx-font-size: 13px;
    -fx-text-fill: #64748b;
    -fx-font-style: italic;
}

/* Domaines d'intérêt tags */
.domaines-tags-container {
    -fx-padding: 8px 0;
}

.domaine-tag {
    -fx-background-color: #e0e7ff;
    -fx-background-radius: 20;
    -fx-padding: 6px 12px;
    -fx-alignment: center;
    -fx-border-color: #6974e8;
    -fx-border-width: 1;
    -fx-border-radius: 20;
}

.domaine-tag-label {
    -fx-text-fill: #4338ca;
    -fx-font-size: 13px;
    -fx-font-weight: 500;
}

.domaine-tag-remove {
    -fx-background-color: transparent;
    -fx-text-fill: #6366f1;
    -fx-font-size: 16px;
    -fx-font-weight: bold;
    -fx-padding: 0 4px;
    -fx-cursor: hand;
    -fx-min-width: 20;
    -fx-min-height: 20;
    -fx-max-width: 20;
    -fx-max-height: 20;
    -fx-background-radius: 10;
}

.domaine-tag-remove:hover {
    -fx-background-color: #c7d2fe;
    -fx-text-fill: #4338ca;
}

/* Button enhancements */
.btn-primary {
    -fx-background-color: linear-gradient(to bottom right, #6974e8, #8f94f6);
    -fx-text-fill: white;
    -fx-background-radius: 12px;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-font-weight: 700;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(105, 116, 232, 0.3), 12, 0, 0, 4);
    -fx-padding: 12px 28px;
    -fx-font-size: 14px;
}

.btn-primary:hover {
    -fx-background-color: linear-gradient(to bottom right, #5b21b6, #7c3aed);
    -fx-effect: dropshadow(gaussian, rgba(105, 116, 232, 0.5), 16, 0, 0, 6);
    -fx-translate-y: -1px;
}

.btn-primary:pressed {
    -fx-background-color: linear-gradient(to bottom right, #4c1d95, #6b21a8);
    -fx-effect: dropshadow(gaussian, rgba(105, 116, 232, 0.25), 8, 0, 0, 2);
    -fx-translate-y: 0px;
}

.btn-primary:disabled {
    -fx-opacity: 0.5;
    -fx-cursor: default;
    -fx-effect: none;
}

.btn-secondary {
    -fx-background-color: #f8fafc;
    -fx-text-fill: #475569;
    -fx-background-radius: 12px;
    -fx-border-color: #e2e8f0;
    -fx-border-width: 2px;
    -fx-font-weight: 600;
    -fx-cursor: hand;
    -fx-padding: 12px 24px;
    -fx-font-size: 14px;
}

.btn-secondary:hover {
    -fx-background-color: #f1f5f9;
    -fx-border-color: #cbd5e1;
    -fx-text-fill: #1e293b;
    -fx-effect: dropshadow(gaussian, rgba(0, 0, 0, 0.05), 8, 0, 0, 2);
    -fx-translate-y: -1px;
}

.btn-secondary:pressed {
    -fx-background-color: #e2e8f0;
    -fx-border-color: #94a3b8;
    -fx-translate-y: 0px;
}

.btn-secondary:disabled {
    -fx-opacity: 0.5;
    -fx-cursor: default;
    -fx-effect: none;
}

/* Success Button */
.btn-success {
    -fx-background-color: linear-gradient(to bottom right, #10b981, #34d399);
    -fx-text-fill: white;
    -fx-background-radius: 12px;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-font-weight: 700;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(16, 185, 129, 0.3), 12, 0, 0, 4);
    -fx-padding: 12px 28px;
    -fx-font-size: 14px;
}

.btn-success:hover {
    -fx-background-color: linear-gradient(to bottom right, #059669, #10b981);
    -fx-effect: dropshadow(gaussian, rgba(16, 185, 129, 0.5), 16, 0, 0, 6);
    -fx-translate-y: -1px;
}

.btn-success:pressed {
    -fx-background-color: linear-gradient(to bottom right, #047857, #059669);
    -fx-effect: dropshadow(gaussian, rgba(16, 185, 129, 0.25), 8, 0, 0, 2);
    -fx-translate-y: 0px;
}

.btn-success:disabled {
    -fx-opacity: 0.5;
    -fx-cursor: default;
    -fx-effect: none;
}

/* Warning Button */
.btn-warning {
    -fx-background-color: linear-gradient(to bottom right, #f59e0b, #fbbf24);
    -fx-text-fill: white;
    -fx-background-radius: 12px;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-font-weight: 700;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(245, 158, 11, 0.3), 12, 0, 0, 4);
    -fx-padding: 12px 28px;
    -fx-font-size: 14px;
}

.btn-warning:hover {
    -fx-background-color: linear-gradient(to bottom right, #d97706, #f59e0b);
    -fx-effect: dropshadow(gaussian, rgba(245, 158, 11, 0.5), 16, 0, 0, 6);
    -fx-translate-y: -1px;
}

.btn-warning:pressed {
    -fx-background-color: linear-gradient(to bottom right, #b45309, #d97706);
    -fx-effect: dropshadow(gaussian, rgba(245, 158, 11, 0.25), 8, 0, 0, 2);
    -fx-translate-y: 0px;
}

.btn-warning:disabled {
    -fx-opacity: 0.5;
    -fx-cursor: default;
    -fx-effect: none;
}

/* Info Button */
.btn-info {
    -fx-background-color: linear-gradient(to bottom right, #3b82f6, #60a5fa);
    -fx-text-fill: white;
    -fx-background-radius: 12px;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-font-weight: 700;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(59, 130, 246, 0.3), 12, 0, 0, 4);
    -fx-padding: 12px 28px;
    -fx-font-size: 14px;
}

.btn-info:hover {
    -fx-background-color: linear-gradient(to bottom right, #2563eb, #3b82f6);
    -fx-effect: dropshadow(gaussian, rgba(59, 130, 246, 0.5), 16, 0, 0, 6);
    -fx-translate-y: -1px;
}

.btn-info:pressed {
    -fx-background-color: linear-gradient(to bottom right, #1d4ed8, #2563eb);
    -fx-effect: dropshadow(gaussian, rgba(59, 130, 246, 0.25), 8, 0, 0, 2);
    -fx-translate-y: 0px;
}

.btn-info:disabled {
    -fx-opacity: 0.5;
    -fx-cursor: default;
    -fx-effect: none;
}

/* Filter/Sort action buttons (CRUD lists) */
.btn-filter {
    -fx-background-color: linear-gradient(to bottom right, #0ea5e9, #38bdf8);
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 10px;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(14, 165, 233, 0.28), 10, 0, 0, 3);
}

.btn-filter:hover {
    -fx-background-color: linear-gradient(to bottom right, #0284c7, #0ea5e9);
    -fx-effect: dropshadow(gaussian, rgba(14, 165, 233, 0.38), 14, 0, 0, 4);
    -fx-translate-y: -1px;
}

.btn-filter:pressed {
    -fx-background-color: linear-gradient(to bottom right, #0369a1, #0284c7);
    -fx-translate-y: 0px;
}

.btn-sort {
    -fx-background-color: linear-gradient(to bottom right, #7c3aed, #8b5cf6);
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 10px;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(124, 58, 237, 0.26), 10, 0, 0, 3);
}

.btn-sort:hover {
    -fx-background-color: linear-gradient(to bottom right, #6d28d9, #7c3aed);
    -fx-effect: dropshadow(gaussian, rgba(124, 58, 237, 0.36), 14, 0, 0, 4);
    -fx-translate-y: -1px;
}

.btn-sort:pressed {
    -fx-background-color: linear-gradient(to bottom right, #5b21b6, #6d28d9);
    -fx-translate-y: 0px;
}

.btn-reset-filters {
    -fx-background-color: linear-gradient(to bottom right, #64748b, #94a3b8);
    -fx-text-fill: white;
    -fx-font-weight: 700;
    -fx-background-radius: 10px;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(100, 116, 139, 0.24), 10, 0, 0, 3);
}

.btn-reset-filters:hover {
    -fx-background-color: linear-gradient(to bottom right, #475569, #64748b);
    -fx-effect: dropshadow(gaussian, rgba(100, 116, 139, 0.34), 14, 0, 0, 4);
    -fx-translate-y: -1px;
}

.btn-reset-filters:pressed {
    -fx-background-color: linear-gradient(to bottom right, #334155, #475569);
    -fx-translate-y: 0px;
}

/* Small Button Variants */
.btn-primary-small {
    -fx-background-color: linear-gradient(to bottom right, #6974e8, #8f94f6);
    -fx-text-fill: white;
    -fx-background-radius: 8px;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-font-weight: 600;
    -fx-cursor: hand;
    -fx-padding: 8px 16px;
    -fx-font-size: 12px;
}

.btn-primary-small:hover {
    -fx-background-color: linear-gradient(to bottom right, #5b21b6, #7c3aed);
    -fx-translate-y: -1px;
}

.btn-secondary-small {
    -fx-background-color: #f8fafc;
    -fx-text-fill: #475569;
    -fx-background-radius: 8px;
    -fx-border-color: #e2e8f0;
    -fx-border-width: 1px;
    -fx-font-weight: 500;
    -fx-cursor: hand;
    -fx-padding: 8px 16px;
    -fx-font-size: 12px;
}

.btn-secondary-small:hover {
    -fx-background-color: #f1f5f9;
    -fx-border-color: #cbd5e1;
    -fx-text-fill: #1e293b;
}

/* Focus indicators */
.form-control:focused,
.btn-primary:focused,
.btn-secondary:focused,
.btn-success:focused,
.btn-danger:focused,
.btn-warning:focused,
.btn-info:focused {
    -fx-effect: dropshadow(gaussian, rgba(105, 116, 232, 0.4), 8, 0, 0, 2);
}

/* Loading states */
.btn-primary:disabled,
.btn-secondary:disabled,
.btn-success:disabled,
.btn-danger:disabled,
.btn-warning:disabled,
.btn-info:disabled {
    -fx-opacity: 0.5;
    -fx-cursor: default;
    -fx-effect: none;
}

/* Success/Error states */
.form-control.success {
    -fx-border-color: #059669;
}

.form-control.error {
    -fx-border-color: #dc2626;
}

/* ── Boutique (Shop) UI ────────────────────────────────────── */
.btn-danger {
    -fx-background-color: linear-gradient(to bottom right, #ef4444, #f87171);
    -fx-text-fill: white;
    -fx-background-radius: 12px;
    -fx-border-color: transparent;
    -fx-border-width: 0;
    -fx-font-weight: 700;
    -fx-cursor: hand;
    -fx-effect: dropshadow(gaussian, rgba(239, 68, 68, 0.3), 12, 0, 0, 4);
    -fx-padding: 12px 28px;
    -fx-font-size: 14px;
}

.btn-danger:hover {
    -fx-background-color: linear-gradient(to bottom right, #dc2626, #ef4444);
    -fx-effect: dropshadow(gaussian, rgba(239, 68, 68, 0.5), 16, 0, 0, 6);
    -fx-translate-y: -1px;
}

.btn-danger:pressed {
    -fx-background-color: linear-gradient(to bottom right, #b91c1c, #dc2626);
    -fx-effect: dropshadow(gaussian, rgba(239, 68, 68, 0.25), 8, 0, 0, 2);
    -fx-translate-y: 0px;
}

.btn-danger:disabled {
    -fx-opacity: 0.5;
    -fx-cursor: default;
    -fx-effect: none;
}

.shop-product-card {
    -fx-background-color: white;
    -fx-background-radius: 18px;
    -fx-border-color: #eef2f7;
    -fx-border-radius: 18px;
    -fx-effect: dropshadow(three-pass-box, rgba(0,0,0,0.06), 18, 0, 0, 6);
}

.shop-product-card:hover {
    -fx-border-color: rgba(105,116,232,0.35);
    -fx-effect: dropshadow(three-pass-box, rgba(105,116,232,0.18), 26, 0, 0, 10);
    -fx-translate-y: -2px;
}

.shop-badge {
    -fx-background-color: #eef2ff;
    -fx-text-fill: #4338ca;
    -fx-padding: 3px 10px;
    -fx-background-radius: 999px;
    -fx-font-size: 11px;
    -fx-font-weight: 700;
}

.shop-badge-success {
    -fx-background-color: #ecfdf5;
    -fx-text-fill: #047857;
}

.shop-badge-danger {
    -fx-background-color: #fff1f2;
    -fx-text-fill: #be123c;
}

.shop-product-name {
    -fx-font-size: 16px;
    -fx-font-weight: 900;
    -fx-text-fill: #0f172a;
}

.shop-product-desc {
    -fx-font-size: 12.5px;
    -fx-text-fill: #64748b;
    -fx-line-spacing: 2px;
}

.shop-product-price {
    -fx-font-size: 16px;
    -fx-font-weight: 900;
    -fx-text-fill: #10b981;
}

.shop-product-stock {
    -fx-font-size: 12px;
    -fx-text-fill: #0f172a;
}

.shop-text-danger {
    -fx-text-fill: #ef4444;
    -fx-font-weight: 800;
}

.shop-in-cart {
    -fx-text-fill: #334155;
    -fx-font-size: 12px;
    -fx-font-weight: 700;
}

.shop-card-actions {
    -fx-alignment: center-left;
}

.shop-icon-btn {
    -fx-min-width: 42px;
    -fx-min-height: 36px;
    -fx-padding: 6px 10px;
}

.shop-add-btn {
    -fx-padding: 10px 14px;
}

.shop-danger-btn {
    -fx-padding: 10px 14px;
}

.shop-detail-title {
    -fx-font-size: 18px;
    -fx-font-weight: 900;
    -fx-text-fill: #0f172a;
}

.shop-detail-image {
    -fx-background-color: #f8fafc;
    -fx-border-color: #e2e8f0;
    -fx-border-radius: 12;
    -fx-background-radius: 12;
}

/* ── Cart UI ──────────────────────────────────────────────── */
.btn-small {
    -fx-padding: 8px 12px;
    -fx-font-size: 12.5px;
}

.cart-table {
    -fx-background-radius: 20px;
    -fx-border-radius: 20px;
}

.cart-table .table-row-cell {
    -fx-cell-size: 72px;
}

.cart-product-cell {
    -fx-alignment: center-left;
}

.cart-product-thumb {
    -fx-background-color: #f8fafc;
    -fx-border-color: #e2e8f0;
    -fx-border-radius: 10;
    -fx-background-radius: 10;
}

.cart-product-name {
    -fx-font-size: 14px;
    -fx-font-weight: 900;
    -fx-text-fill: #0f172a;
}

.cart-badge {
    -fx-font-size: 10.5px;
}

.cart-actions {
    -fx-alignment: center-left;
}

.cart-icon-btn {
    -fx-min-width: 42px;
    -fx-min-height: 34px;
}

.cart-remove-btn {
    -fx-padding: 8px 14px;
}

.qty-spinner {
    -fx-background-color: transparent;
}

.qty-spinner .text-field {
    -fx-background-radius: 10px;
    -fx-border-radius: 10px;
    -fx-border-color: #e2e8f0;
    -fx-background-color: #ffffff;
    -fx-padding: 6px 8px;
}

.qty-spinner .increment-arrow-button,
.qty-spinner .decrement-arrow-button {
    -fx-background-color: #f1f5f9;
    -fx-background-radius: 10px;
    -fx-border-color: #e2e8f0;
    -fx-border-radius: 10px;
}

.cart-summary-card {
    -fx-background-color: linear-gradient(to right, rgba(105,116,232,0.12), rgba(143,148,246,0.12));
    -fx-border-color: rgba(105,116,232,0.25);
    -fx-border-radius: 16px;
    -fx-background-radius: 16px;
    -fx-padding: 12px 16px;
}

.cart-summary-title {
    -fx-text-fill: #475569;
    -fx-font-size: 12px;
    -fx-font-weight: 700;
}

.cart-summary-meta {
    -fx-text-fill: #64748b;
    -fx-font-size: 12px;
    -fx-font-weight: 600;
}

.cart-summary-value {
    -fx-text-fill: #0f172a;
    -fx-font-size: 18px;
    -fx-font-weight: 900;
}

/* ── Cart page & suggestions ─────────────────────────────── */
.cart-page-scroll {
    -fx-background-color: transparent;
    -fx-background: transparent;
}

.cart-page-scroll > .viewport {
    -fx-background-color: transparent;
}

.cart-page-root {
    -fx-min-width: 560;
}

.cart-header-row {
    -fx-wrap-text: false;
}

.cart-basket-panel {
    -fx-background-color: #ffffff;
    -fx-background-radius: 14px;
    -fx-border-color: #e2e8f0;
    -fx-border-radius: 14px;
    -fx-border-width: 1px;
    -fx-padding: 18px;
}

.cart-empty-label {
    -fx-font-size: 15px;
    -fx-text-fill: #64748b;
    -fx-alignment: center;
    -fx-padding: 24px;
}

.cart-total-row {
    -fx-padding: 8px 4px 0 4px;
}

.cart-suggestions-panel {
    -fx-background-color: #f8fafc;
    -fx-background-radius: 16px;
    -fx-border-color: #e2e8f0;
    -fx-border-radius: 16px;
    -fx-border-width: 1px;
    -fx-padding: 18px;
}

.cart-suggestions-title-row {
    -fx-padding: 0 0 2 0;
}

.cart-suggestions-heading {
    -fx-font-size: 17px;
    -fx-font-weight: 800;
    -fx-text-fill: #0f172a;
}

.cart-suggestions-scroll {
    -fx-background-color: #ffffff;
    -fx-background: #ffffff;
    -fx-border-color: #e2e8f0;
    -fx-border-radius: 12px;
    -fx-border-width: 1px;
    -fx-padding: 0;
}

.cart-suggestions-scroll > .viewport {
    -fx-background-color: #ffffff;
}

.cart-suggestions-inner {
    -fx-background-color: #ffffff;
}

.cart-no-suggestions {
    -fx-padding: 10px 8px 4 8px;
}

.cart-no-suggestions-title {
    -fx-font-size: 13px;
    -fx-font-weight: 700;
    -fx-text-fill: #64748b;
}

.cart-no-suggestions-sub {
    -fx-font-size: 12px;
    -fx-text-fill: #94a3b8;
    -fx-wrap-text: true;
    -fx-text-alignment: center;
    -fx-max-width: 520px;
}

.cart-suggestions-toolbar-wrap {
    -fx-spacing: 8px;
}

.cart-suggestions-filter-hint {
    -fx-font-size: 12px;
    -fx-font-weight: 600;
    -fx-text-fill: #3730a3;
    -fx-wrap-text: true;
    -fx-background-color: rgba(99, 102, 241, 0.14);
    -fx-background-radius: 10px;
    -fx-padding: 8px 12px;
    -fx-border-color: rgba(79, 70, 229, 0.35);
    -fx-border-radius: 10px;
    -fx-border-width: 1px;
}

.cart-suggestions-toolbar {
    -fx-alignment: center-left;
    -fx-spacing: 10px;
    -fx-padding: 0 0 4 0;
}

.cart-suggestions-count {
    -fx-font-size: 12px;
    -fx-font-weight: 700;
    -fx-text-fill: #334155;
}

/* Tri suggestions : couleurs distinctes */
.cart-sort-btn {
    -fx-font-size: 11.5px;
